fn encodeAttentionHalf(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    a: ForwardBlockArgsT(Config.WeightBuffer),
) void {
    encodeAttentionProjections(
        Config,
        device,
        encoder,
        pipelines,
        a,
    );
    encodeAttentionGather(
        Config,
        device,
        encoder,
        pipelines,
        a,
    );
}

/// Encode RMSNorm → Q/K/V projections → QK norms.
/// RoPE and KV cache update follow in a separate helper
/// to stay within the 70-line function limit.
fn encodeAttentionProjections(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    a: ForwardBlockArgsT(Config.WeightBuffer),
) void {
    const kv_qmv = QMVDims{
        .M = Config.kv_dim,
        .K = Config.hidden_size,
        .group_size = Config.group_size,
    };
    const q_qmv = QMVDims{
        .M = Config.query_dim,
        .K = Config.hidden_size,
        .group_size = Config.group_size,
    };
    // Fused norm needs K <= 4096 for threadgroup memory
    // and both single + pair pipelines available.
    const can_fuse_norm = comptime (Config.hidden_size % Config.group_size == 0) and
        (Config.hidden_size <= 4096) and
        (Config.hidden_size >= 256) and
        (Config.hidden_size / 32 <= Config.group_size);
    const use_fused_norm =
        if (comptime Config.quant_format == .q4_mlx)
            can_fuse_norm and
                device.spec_q4mv_fused_norm_f16io != null and
                device.spec_q4mv_fused_norm_f16io.?
                    .max_threads_per_group >= 512 and
                device.spec_q4mv_fused_norm_pair_f16io != null and
                device.spec_q4mv_fused_norm_pair_f16io.?
                    .max_threads_per_group >= 512 and
                q_qmv.K == device.spec_q4_hidden_K
        else
            can_fuse_norm and
                device.spec_qmv_fused_norm_f16io != null and
                device.spec_qmv_fused_norm_f16io.?
                    .max_threads_per_group >= 512 and
                device.spec_qmv_fused_norm_pair_f16io != null and
                device.spec_qmv_fused_norm_pair_f16io.?
                    .max_threads_per_group >= 512 and
                q_qmv.K == device.spec_hidden_K;
    if (use_fused_norm) {
        encodeAttnProjFusedNorm(
            Config,
            device,
            encoder,
            a,
            q_qmv,
            kv_qmv,
        );
    } else {
        encodeAttnProjSeparateNorm(
            Config,
            device,
            encoder,
            pipelines,
            a,
            q_qmv,
            kv_qmv,

fn encodeRoPEAndKVCache(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    a: ForwardBlockArgs,
) void {
    std.debug.assert(
        a.position < Config.max_context_length,
    );
    std.debug.assert(Config.head_dim % 2 == 0);
    // Q RoPE: applied in-place (Q is read by GQA attention).
    dispatchRoPE(device, encoder, pipelines.rope_f16, a.q, .{
        .num_heads = Config.num_query_heads,
        .head_dim = Config.head_dim,
        .position = a.position,
        .rope_theta = Config.rope_theta,
    });
    // Fused RoPE K + KV cache update: applies RoPE to K and
    // writes both K and V directly to their caches.  Saves
    // 1 dispatch + 1 barrier vs separate rope_k + cache_update.
    dispatchFusedRoPEKVCache(
        device,
        encoder,
        pipelines.fused_rope_k_kv_cache_f16,
        a.k,
        a.v,
        a.k_cache,
        a.v_cache,
        .{
            .num_kv_heads = Config.num_kv_heads,
            .head_dim = Config.head_dim,
            .position = a.position,
            .max_context_length = Config.max_context_length,
            .rope_theta = Config.rope_theta,
        },
    );
    // Single barrier: wait for both Q RoPE and fused K/V
    // cache write before GQA attention reads Q and k/v caches.
    bufferBarrier(encoder);
}

/// Encode GQA attention → O projection → residual add.
/// Reads from Q buffer and KV cache written by
/// `encodeAttentionProjections`.
fn encodeAttentionGather(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    a: ForwardBlockArgsT(Config.WeightBuffer),
) void {
    // Use the fused kernel that applies Q/K norm + RoPE +
    // KV cache update inside GQA when seq_len fits in TG
    // memory.  Falls back to separate dispatches otherwise.
    const TG_SEQ_LIMIT: u32 = 1024;
    if (a.seq_len <= TG_SEQ_LIMIT) {
        dispatchGQAAttentionFusedTG(
            device,
            encoder,
            pipelines.gqa_attention_fused_f16io_tg,
            a.q,
            a.k_cache,
            a.v_cache,
            a.attn_out,
            a.k,
            a.v,
            a.q_norm_scale,
            a.k_norm_scale,
            .{
                .num_query_heads = Config.num_query_heads,
                .num_kv_heads = Config.num_kv_heads,
                .head_dim = Config.head_dim,
                .seq_len = a.seq_len,
                .max_context_length = Config.max_context_length,
                .heads_per_kv_group = Config.heads_per_kv_group,
                .position = a.position,
                .eps = 1e-6,
                .rope_theta = Config.rope_theta,
            },
        );
    } else {
        // Long-sequence fallback: separate norm+RoPE+cache,
        // then the scratch-based GQA kernel.
        dispatchFusedNormRoPE(
            device,
            encoder,
            pipelines.fused_norm_rope_f16,
            a.q,
            a.q_norm_scale,
            .{
                .num_heads = Config.num_query_heads,
                .head_dim = Config.head_dim,
                .position = a.position,
                .eps = 1e-6,
                .rope_theta = Config.rope_theta,
            },
        );
        dispatchFusedKNormRoPEKVCache(
            device,
            encoder,
            pipelines.fused_k_norm_rope_kv_cache_f16,
            a.k,
            a.v,
            a.k_cache,
            a.v_cache,
            a.k_norm_scale,
            .{
                .num_kv_heads = Config.num_kv_heads,
                .head_dim = Config.head_dim,
                .position = a.position,
                .max_context_length = Config.max_context_length,
                .eps = 1e-6,
                .rope_theta = Config.rope_theta,
            },
        );
        bufferBarrier(encoder);
        dispatchGQAAttention(
            device,
            encoder,
            pipelines.gqa_attention_f16io,
            a.q,
            a.k_cache,
            a.v_cache,
            a.attn_out,
            a.attn_scratch,
            .{
                .num_query_heads = Config.num_query_heads,
                .num_kv_heads = Config.num_kv_heads,
                .head_dim = Config.head_dim,
                .seq_len = a.seq_len,
                .max_context_length = Config.max_context_length,
                .heads_per_kv_group = Config.heads_per_kv_group,
            },
        );
    }
    bufferBarrier(encoder);
    // Fused QMV + residual accumulate: the O-projection result
    // is added directly to the f32 residual (residual[row] += acc)
    // instead of writing f16 to proj_out then dispatching
    // residual_add_f16.  Saves one dispatch + one barrier.
    const o_dims = QMVDims{
        .M = Config.hidden_size,
        .K = Config.query_dim,
        .group_size = Config.group_size,
    };
    if (comptime Config.quant_format == .q4_mlx) {
        dispatchQ4MVf16ioResadd(
            device,
            encoder,
            a.o_proj,
            a.attn_out,
            a.residual,
            o_dims,
        );
    } else {
        dispatchQMVf16ioResadd(
            device,
            encoder,
            a.o_proj,
            a.attn_out,
            a.residual,
            o_dims,
        );
    }
    bufferBarrier(encoder);
}

