/// Extract lower 4 nibbles (bits 0-15) as float4.
inline float4 extract_nibs_lo(uint32_t word) {
    return float4(
        float(word & 0xFu),
        float((word >> 4) & 0xFu),
        float((word >> 8) & 0xFu),
        float((word >> 12) & 0xFu)
    );
}

/// Extract upper 4 nibbles (bits 16-31) as float4.
inline float4 extract_nibs_hi(uint32_t word) {
    return float4(
        float((word >> 16) & 0xFu),
        float((word >> 20) & 0xFu),
        float((word >> 24) & 0xFu),
        float((word >> 28) & 0xFu)
    );
}

